+        id: "mock",
+        model: "mock-embed",
+        embedQuery: async () => [0.1, 0.2, 0.3],
+        embedBatch: async (texts: string[]) => {
+          if (shouldFail) {
+            throw new Error("embedding failure");
+          }
+          return texts.map((_, index) => [index + 1, 0, 0]);
